INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-814ced5a-moex-00338', 'elementary-814ced5a', 'elementary-814ced5a-moex-113-34c7f7f6', 'sub-elementary-814ced5a-03', NULL, 'single_choice', '「我第一遭清楚看到這群水鳥的眼神。每一隻濱鷸的眼神，充滿著陌生、不馴與無可言喻的 神祕。對於賞鳥人而言，眼神是鳥最生動、也最無法觀察的地方。拍攝野鳥的人也以抓住牠 的眼神為第一要素。這是我第一次強烈感受牠們身上散發出的光澤，從來沒有見過如此純然 灰褐的色彩。這種平實的灰褐一直是牠們忍受酷寒，免受敵害，保護牠們從北方千里迢迢抵 臨的顏色。灰褐代表了安全，也象徵著遷徙、旅行、流浪冒險的顏色。這種顏色不是底片或 是顏料所能拍攝、渲染得體，完滿表達出來的。」 下列敘述，符合上文觀點的是：', '["濱鷸平實的顏色，同時代表流浪冒險與安全", "找到最近的觀察距離，是拍攝野鳥的第一要素", "對賞鳥人而言，濱鷸最大的特色是身上散發出的光澤", "對作者而言，觀察濱鷸的眼神比身上的光澤來得重要 灰褐羽毛象徵濱鷸的生命經驗，這是相機無法傳達的"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:52+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00339', 'elementary-814ced5a', 'elementary-814ced5a-moex-113-34c7f7f6', 'sub-elementary-814ced5a-03', NULL, 'single_choice', '「古代希臘哲學家亞里斯多德說：『快樂就是生命的意義和目的，也是人類生存的總目標』； 還有一位奧妙的悲觀主義者，德國哲學家叔本華的一句智慧之言：『快樂乃是健康所開放的 花朵，而健康則從勤勞、節慾、衛生產生。』一點也不假，健康必須力求身心兩健，保養生 理的健康，必也同時保持心理的健全，才能整合身心兩者的愉快，延年益壽。」 根據上文，下列敘述適當的是：', '["生命的意義和目的，在於實踐自己的願望", "勤奮地工作，可以彰顯生命的意義和目的", "做好環境清潔，是讓自己獲得快樂的捷徑", "同時保持生理和心理健康，可以延年益壽 人生最大的快樂，來自於擁有樂觀與智慧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:52+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00340', 'elementary-814ced5a', 'elementary-814ced5a-moex-113-34c7f7f6', 'sub-elementary-814ced5a-03', NULL, 'single_choice', '「『核心素養』是社會群體成員共有的知識、能力與態度，是全方位的素養；『專門素養』 是特定行業人員所具備的特定行業或專門職業的專門素養之知識、能力與態度。『核心素養』 主要目的是強調社會功能，以建立功能健全的社會；『專門素養』主要目的是強調個人具備 特定行業所需的素養，以加入特定專門職業團體，以協助個人獲得成功的生活。」 根據上文，下列選項何者對素養類別的判斷正確？', '["核心素養：開車時願意禮讓行人", "專門素養：能與他人溝通並互動", "核心素養：可以自行研發新產品", "專門素養：能成功行銷工商百貨 核心素養：開發水產養殖新方法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:52+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00341', 'elementary-814ced5a', 'elementary-814ced5a-moex-113-c2172ccd', 'sub-elementary-814ced5a-04', NULL, 'single_choice', '美國的圖書館學教育是由下列那一個機構辦理專業認可，對相關系所定期進行專業評鑑與監督，以使圖書 館界與圖書資訊學教育關連，並保證圖書資訊學教育專業品質？', '["洛克斐勒基金會", "卡內基基金會", "美國圖書館學會", "美國資訊科學暨科技學會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:52+00:00", "source_pdf_sha1": "c12e57de2392", "answer_pdf_sha1": "e519041e32d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "505", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00342', 'elementary-814ced5a', 'elementary-814ced5a-moex-113-c2172ccd', 'sub-elementary-814ced5a-04', NULL, 'single_choice', '下列那位資訊科學先驅曾經推動線上合作編目計畫，成為OCLC的創建者，爾後被尊稱為「OCLC之父」？', '["CyrilW.Cleverdon", "BrendaDervin", "FrederickG.Kilgour", "CalvinN.Mooers"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:52+00:00", "source_pdf_sha1": "c12e57de2392", "answer_pdf_sha1": "e519041e32d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "505", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00343', 'elementary-814ced5a', 'elementary-814ced5a-moex-113-c2172ccd', 'sub-elementary-814ced5a-04', NULL, 'single_choice', '關於文章處理費（ArticleProcessingCharge,APC）的敘述，下列何者錯誤？', '["所有的開放取用期刊都會向作者收取文章處理費以支援期刊出版相關費用", "有些學術圖書館為積極推動開放取用期刊的使用與投稿，會補助文章處理費給作者投稿於開放取用期刊", "期刊收取的文章處理費，用以支付編務、印務，以及學術傳播之行銷等項目", "各出版社的文章處理費不盡相同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:52+00:00", "source_pdf_sha1": "c12e57de2392", "answer_pdf_sha1": "e519041e32d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "505", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00344', 'elementary-814ced5a', 'elementary-814ced5a-moex-113-c2172ccd', 'sub-elementary-814ced5a-04', NULL, 'single_choice', 'T.D.Wilson曾經提出一個資訊行為的巢狀模式（nestedmodelofinformationbehavior），在最內圈的是下 列何者？', '["資訊使用行為（informationusebehavior）", "被動資訊獲得行為（passiveinformationacquisitionbehavior）", "資訊尋求行為（informationseekingbehavior）", "資訊查詢行為（informationsearchingbehavior）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:52+00:00", "source_pdf_sha1": "c12e57de2392", "answer_pdf_sha1": "e519041e32d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "505", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00345', 'elementary-814ced5a', 'elementary-814ced5a-moex-113-c2172ccd', 'sub-elementary-814ced5a-04', NULL, 'single_choice', '有關資訊素養之敘述，下列何者錯誤？', '["Societyof College, National and UniversityLibraries（SCONUL）制訂「高等教育資訊素養七柱模式」 （TheSevenPillarsofInformationLiteracyforHigherEducation）", "InternationalFederationofLibraryAssociationsandInstitutions（IFLA）發布高等教育資訊素養能力標準 （InformationLiteracyCompetencyStandardsforHigherEducation）", "Association of College and Research Libraries（ACRL）提出高等教育資訊素養架構（Framework for InformationLiteracyforHigherEducation）", "UnitedNationsEducationalScientificandCulturalOrganization（UNESCO）倡導資訊素養指標（Information LiteracyIndicators）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:52+00:00", "source_pdf_sha1": "c12e57de2392", "answer_pdf_sha1": "e519041e32d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "505", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00346', 'elementary-814ced5a', 'elementary-814ced5a-moex-113-c2172ccd', 'sub-elementary-814ced5a-04', NULL, 'single_choice', '學習者一面接受新訊息、學習新技能，而後立即能為新訊息及新技能賦予新的意義，甚至可再將之傳播給 他人，這種學習概念稱之為下列何者？', '["創新學習", "多元學習", "開放學習", "學習如何學習"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:52+00:00", "source_pdf_sha1": "c12e57de2392", "answer_pdf_sha1": "e519041e32d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "505", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00347', 'elementary-814ced5a', 'elementary-814ced5a-moex-113-c2172ccd', 'sub-elementary-814ced5a-04', NULL, 'single_choice', '《我國公共圖書館工作人員專業知能研訂芻議》就我國公共圖書館館員所需具備之專業知能進行研訂，並 提出指標提供參考。該書是由下列那一個機構所出版？', '["中華民國圖書館學會", "國家圖書館", "國立臺灣圖書館", "臺北市立圖書館"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:52+00:00", "source_pdf_sha1": "c12e57de2392", "answer_pdf_sha1": "e519041e32d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "505", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
